(function( $ ) {
  "use strict";

  $.fn.counterUp = function( options ) {

    // Defaults
    var settings = $.extend({
      'time': 400,
      'delay': 10
    }, options);

    return this.each(function() {

      var $this = $(this);
      var updated = false;
      var updateCount = function() {

        if (updated) return;
        updated = true;

        var max = parseInt($this.attr('data-count'),10);
        var start = parseInt($this.text(),10) || 0;
        var commas = !!$this.attr('data-commas');
        var duration = !!settings.time ? settings.time : 400;
        var delay = !!settings.delay ? settings.delay : 10;
        var range = max - start;
        var increment = end / (duration / delay);
        var decrement = range / (duration / delay);
        var text = $this.text();
        var isMoney = text.indexOf("$") > -1;
        var isPercentage = text.indexOf("%") > -1;
        var isFloating = text.indexOf(".") > -1;

        // Text prefix and suffix
        var prefix = text.split(isFloating ? ".": isPercentage ? "%" : isMoney ? "$" : "")[0];
        if (isMoney) prefix += "$";

        var suffix = !!isFloating ? "." + text.split(".")[1].replace(/[0-9]/g, '0').substr(0, text.split(".")[1].length) : isPercentage ? "%" : "";

        var update = setInterval(function() {

          start += decrement;
          if (start >= max) {
            clearInterval(update);
            start = max;
          }

          var text = prefix + Math.floor(start).toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",") + suffix;

          $this.text(text);

        }, delay);

      };

      $(window).scroll(function() {
        if (!updated && $(window).scrollTop() + $(window).height() >= $this.offset().top) {
          updateCount();
        }
      });

      // Check on init
      if ($(window).scrollTop() + $(window).height() >= $this.offset().top) {
        updateCount();
      }

    });

  };

})( jQuery );
